import { Group } from '@visx/group';
import { type MouseEventHandler, useRef } from 'react';

import {
  MARKER_STROKE_WIDTH,
  MARKER_STROKE_COLOR,
  MARKER_RADIUS,
} from './constants.js';
import { useId } from '../../../../../core/hooks/useId.js';
import { useMouseHover } from '../../../hooks/useMouseHover.js';
import { ThresholdBrightnessFilter } from '../ThresholdBrightnessFilter.js';

export interface PillMarkerProps {
  y0: number;
  y1: number;
  x: number;
  color: string;
  opacity: number;
  onMouseMove: MouseEventHandler;
  onMouseLeave: MouseEventHandler;
}

export const PillMarker = (props: PillMarkerProps) => {
  const { x, y0, y1, color, onMouseMove, onMouseLeave, opacity } = props;

  const rectRef = useRef<SVGRectElement>(null);
  const hovered = useMouseHover(rectRef);
  const id = useId();

  const brightnessFilterId = `threshold-pill-marker-filter-${id}`;

  return (
    <Group>
      <ThresholdBrightnessFilter id={brightnessFilterId} />
      <rect
        role="graphics-symbol"
        aria-label="pill marker"
        ref={rectRef}
        x={x}
        y={
          Math.abs(y1 - y0) > MARKER_RADIUS * 2
            ? Math.min(y0, y1)
            : (y0 + y1) / 2 - MARKER_RADIUS
        }
        height={Math.max(Math.abs(y1 - y0), MARKER_RADIUS * 2)}
        width={MARKER_RADIUS * 2}
        fill={color}
        rx={MARKER_RADIUS}
        opacity={opacity}
        filter={hovered ? `url(#${brightnessFilterId})` : undefined}
        stroke={MARKER_STROKE_COLOR}
        strokeWidth={MARKER_STROKE_WIDTH}
        onMouseMove={onMouseMove}
        onMouseLeave={onMouseLeave}
      />
    </Group>
  );
};
